/**
 * SERVIÇO DE VOZ NATIVO OTIMIZADO
 * Focado em estabilidade, clareza e cumprimento estrito da sequência de duas chamadas.
 */

let isGlobalSpeaking = false;
const callLockMap = new Map<string, number>();

/**
 * Busca por uma voz feminina em pt-BR com fallback robusto.
 */
const getPortugueseVoice = (): SpeechSynthesisVoice | null => {
  if (!('speechSynthesis' in window)) return null;
  const voices = window.speechSynthesis.getVoices();

  // Preferência por vozes femininas conhecidas
  const preferred = ['Luciana', 'Maria', 'Heloisa', 'Vitoria', 'Google português do Brasil'];
  const ptBR = voices.filter(v => v.lang.includes('pt-BR'));

  if (ptBR.length === 0) return null;

  for (const name of preferred) {
    const found = ptBR.find(v => v.name.includes(name));
    if (found) return found;
  }

  return ptBR[0];
};

/**
 * Executa a síntese de voz de forma assíncrona com promessa.
 */
const speakText = (text: string, rate = 1.0): Promise<void> => {
  return new Promise((resolve) => {
    const utterance = new SpeechSynthesisUtterance(text);
    const voice = getPortugueseVoice();

    if (voice) utterance.voice = voice;
    utterance.lang = 'pt-BR';
    utterance.rate = rate;
    utterance.pitch = 1.0;
    utterance.volume = 1.0;

    utterance.onend = () => resolve();
    utterance.onerror = () => resolve();

    window.speechSynthesis.speak(utterance);
  });
};

/**
 * Anuncia a chamada do cliente: Duas chamadas claras e sequenciais.
 * Ex: "Senha P-001, DIEGO SILVA" ... pausa ... "Senha P-001, DIEGO SILVA. Favor comparecer ao atendimento."
 */
export const announceCustomerCall = async (customerName: string, password: string, ticketId: string) => {
  if (!('speechSynthesis' in window)) return;

  const now = Date.now();
  const lastCallTime = callLockMap.get(ticketId) || 0;

  // Prevenção de sobreposição de áudio e spam de chamadas (lock de 5s por ticket)
  if (isGlobalSpeaking || (now - lastCallTime < 5000)) {
    console.log(`[VOZ] Chamada ignorada para ${customerName} (Já em curso ou muito recente)`);
    return;
  }

  isGlobalSpeaking = true;
  callLockMap.set(ticketId, now);

  try {
    // Cancela qualquer resíduo de áudio anterior para evitar delays
    window.speechSynthesis.cancel();

    // Pequeno delay inicial para garantir que o cancelamento foi processado
    await new Promise(r => setTimeout(r, 100));

    const nameForVoice = customerName.toLowerCase();
    const passwordForVoice = password.split('').join(' '); // Melhora a dicção da senha (P 0 0 1)

    // PRIMEIRA CHAMADA (Curta e Direta)
    await speakText(`Atenção: Senha ${passwordForVoice}. ${nameForVoice}.`, 0.95);

    // PAUSA ENTRE CHAMADAS (Instante de silêncio para atenção)
    await new Promise(r => setTimeout(r, 1200));

    // SEGUNDA CHAMADA (Completa com Instrução)
    await speakText(`Senha ${passwordForVoice}. ${nameForVoice}. Favor comparecer ao atendimento externo.`, 0.9);

  } catch (error) {
    console.error("[VOZ] Erro na síntese:", error);
  } finally {
    isGlobalSpeaking = false;
    console.log(`[VOZ] Sequência finalizada para: ${customerName}`);
  }
};

import React, { useEffect, useState, useMemo, useRef } from 'react';
import { Ticket, TicketStatus, Priority } from '../types';
import { announceCustomerCall } from '../services/geminiService';

interface CustomerDashboardProps {
  tickets: Ticket[];
}

const CustomerDashboard: React.FC<CustomerDashboardProps> = ({ tickets = [] }) => {
  const [lastCalled, setLastCalled] = useState<Ticket | null>(null);
  const [blink, setBlink] = useState(false);

  // Referência para rastrear quais eventos de chamada (ID + Timestamp) já foram processados
  // Isso evita que o sistema re-anuncie o mesmo ticket se a lista de tickets atualizar por outros motivos.
  const processedEventsRef = useRef<Set<string>>(new Set());

  // Fila de anúncios para garantir que, se vários forem chamados ao mesmo tempo, todos sejam falados em ordem
  const [announcementQueue, setAnnouncementQueue] = useState<Ticket[]>([]);
  const isAnnouncingRef = useRef(false);

  useEffect(() => {
    if (!tickets || tickets.length === 0) return;

    // 1. Identifica tickets em status CALLED
    const currentlyCalled = tickets.filter(t => t.status === TicketStatus.CALLED && t.callTime);

    const newAnnouncements: Ticket[] = [];

    currentlyCalled.forEach(ticket => {
      const eventId = `${ticket.id}-${new Date(ticket.callTime!).getTime()}`;

      // Se este evento específico (Ticket + Hora da Chamada) ainda não foi processado
      if (!processedEventsRef.current.has(eventId)) {
        processedEventsRef.current.add(eventId);
        newAnnouncements.push(ticket);
      }
    });

    if (newAnnouncements.length > 0) {
      // Ordena os novos acionamentos pelo tempo de chamada
      newAnnouncements.sort((a, b) => new Date(a.callTime!).getTime() - new Date(b.callTime!).getTime());
      setAnnouncementQueue(prev => [...prev, ...newAnnouncements]);
    }
  }, [tickets]);

  // Processador da fila de anúncios
  useEffect(() => {
    const processQueue = async () => {
      if (announcementQueue.length === 0 || isAnnouncingRef.current) return;

      isAnnouncingRef.current = true;
      const nextTicket = announcementQueue[0];

      // Atualiza o visual
      setLastCalled(nextTicket);
      setBlink(true);

      // Dispara a voz (que faz as 2 chamadas internamente)
      await announceCustomerCall(nextTicket.customerName, nextTicket.password, nextTicket.id);

      // Mantém o blink por mais alguns segundos após a voz terminar
      setTimeout(() => {
        setBlink(false);
        setAnnouncementQueue(prev => prev.slice(1));
        isAnnouncingRef.current = false;
      }, 3000);
    };

    processQueue();
  }, [announcementQueue]);

  const ready = useMemo(() => tickets.filter(t => t.status === TicketStatus.READY), [tickets]);
  const inSeparation = useMemo(() => tickets.filter(t => t.status === TicketStatus.IN_SEPARATION), [tickets]);
  const waiting = useMemo(() => tickets.filter(t => t.status === TicketStatus.WAITING_SEPARATION), [tickets]);

