                   <div className="h-1.5 w-12 bg-white/50 rounded-full animate-pulse"></div>
                   <p className="text-white font-black animate-pulse text-2xl uppercase tracking-widest">Favor dirigir-se ao Atendimento</p>
                   <div className="h-1.5 w-12 bg-white/50 rounded-full animate-pulse"></div>
