import { GoogleGenAI, Modality } from "@google/genai";

/**
 * SERVIÇO DE VOZ GEMINI TTS OTIMIZADO
 * Utiliza o modelo gemini-2.5-flash-preview-tts para anúncios profissionais.
 */

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
let isGlobalSpeaking = false;
const callLockMap = new Map<string, number>();
let audioContext: AudioContext | null = null;

/**
 * Utilitário para decodificar base64 manual (conforme diretrizes)
 */
function decodeBase64(base64: string): Uint8Array {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

/**
 * Utilitário para decodificar áudio PCM bruto de 16-bits (conforme diretrizes)
 */
async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

/**
 * Executa a síntese de voz via Gemini 2.5 Flash TTS.
 */
const speakWithGemini = async (text: string): Promise<void> => {
  try {
    if (!audioContext) {
      audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
    }

    if (audioContext.state === 'suspended') {
      await audioContext.resume();
    }

    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName: 'Kore' }, // Voz feminina clara e profissional
          },
        },
      },
    });

    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (base64Audio) {
      const audioBuffer = await decodeAudioData(
        decodeBase64(base64Audio),
        audioContext,
        24000,
        1,
      );

      const source = audioContext.createBufferSource();
      source.buffer = audioBuffer;
      source.connect(audioContext.destination);

      return new Promise((resolve) => {
        source.onended = () => resolve();
        source.start();
      });
    }
  } catch (error) {
    console.error("[VOZ GEMINI] Erro na síntese de áudio:", error);
  }
};

/**
 * Anuncia a chamada do cliente seguindo a regra de duas chamadas sequenciais.
 * O Gemini processa o texto para uma dicção humana e natural.
 */
export const announceCustomerCall = async (customerName: string, password: string, ticketId: string) => {
  const now = Date.now();
  const lastCallTime = callLockMap.get(ticketId) || 0;

  // Prevenção de concorrência de áudio e spam (lock de 5s por ticket)
  if (isGlobalSpeaking || (now - lastCallTime < 5000)) {
    console.log(`[VOZ] Chamada ignorada para ${customerName} (Já em curso ou muito recente)`);
    return;
  }

  isGlobalSpeaking = true;
  callLockMap.set(ticketId, now);

  try {
    const nameForVoice = customerName.toUpperCase();
    const passwordForVoice = password.split('').join(' '); // Melhora a soletração da senha (ex: P 0 0 1)

    // PRIMEIRA CHAMADA (Imediata)
    await speakWithGemini(`Atenção: Senha ${passwordForVoice}. ${nameForVoice}.`);

    // PAUSA ENTRE CHAMADAS (Instante de silêncio para fixação)
    await new Promise(r => setTimeout(r, 1200));

    // SEGUNDA CHAMADA (Completa com Instrução)
    await speakWithGemini(`Repetindo: Senha ${passwordForVoice}. ${nameForVoice}. Favor comparecer ao atendimento externo.`);

  } catch (error) {
    console.error("[VOZ] Erro na sequência de anúncios:", error);
  } finally {
    isGlobalSpeaking = false;
    console.log(`[VOZ] Sequência finalizada com sucesso para: ${customerName}`);
  }
};

